"use strict";(self.webpackChunkPradocument=self.webpackChunkPradocument||[]).push([[6334],{6863:(n,s,a)=>{a.r(s),a.d(s,{data:()=>e});const e={key:"v-0a3f9676",path:"/module/vue/Vue2%E5%92%8CVue3%E7%9A%84%E5%8C%BA%E5%88%AB.html",title:"",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:2,title:"Vue2和Vue3的区别",slug:"vue2和vue3的区别",children:[]}],filePathRelative:"module/vue/Vue2和Vue3的区别.md",git:{updatedTime:1657620056e3,contributors:[{name:"孤城致幻",email:"Xast@123456",commits:1}]}}},9185:(n,s,a)=>{a.r(s),a.d(s,{default:()=>t});const e=(0,a(6252).uE)('<h2 id="vue2和vue3的区别" tabindex="-1"><a class="header-anchor" href="#vue2和vue3的区别" aria-hidden="true">#</a> Vue2和Vue3的区别</h2><h5 id="_1-vue2和vue3双向数据绑定原理发生了改变" tabindex="-1"><a class="header-anchor" href="#_1-vue2和vue3双向数据绑定原理发生了改变" aria-hidden="true">#</a> 1：vue2和vue3双向数据绑定原理发生了改变</h5><p><code>vue2</code>的双向数据绑定是利用<code>ES5</code>的一个API<code>Object.definePropert()</code> 对数据进行劫持，结合发布订阅模式的方式来实现的。<br><code>vue3</code>中使用了<code>ES6</code>的<code>Proxy</code> API对数据代理。<br> 相比<code>vue2.x</code>，使用<code>proxy</code>的优势如下：</p><ul><li><code>defineProperty</code>只能监听某个属性，不能对全对象监听</li><li>可以省去<code>for in</code>，闭包等内容来提升效率(直接绑定整个对象即可)</li><li>可以监听数组，不用再去单独的对数组做特异性操作<code>vue3.x</code>可以检测到数组内部数据的变化。</li></ul><h5 id="_2-vue2和vue3定义数据变量和方法的改变" tabindex="-1"><a class="header-anchor" href="#_2-vue2和vue3定义数据变量和方法的改变" aria-hidden="true">#</a> 2: vue2和vue3定义数据变量和方法的改变</h5><p>在<code>vue2</code>中定义数据变量是<code>data(){}</code>，创建的方法要在<code>methods:{}</code>中。<br> 而在<code>vue3</code>中直接在<code>setup(){}</code>中，在这里面定义的变量和方法因为最终要在模板中使用，所以最后都得 <code>return</code>。<br> 如：</p><div class="language-vue ext-vue line-numbers-mode"><pre class="language-vue"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>script</span> <span class="token attr-name">lang</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>ts<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span><span class="token script"><span class="token language-javascript">\n<span class="token keyword">import</span> <span class="token punctuation">{</span> defineComponent<span class="token punctuation">,</span> ref <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;vue&#39;</span><span class="token punctuation">;</span>\n\n<span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token function">defineComponent</span><span class="token punctuation">(</span><span class="token punctuation">{</span>\n  <span class="token literal-property property">name</span><span class="token operator">:</span> <span class="token string">&#39;App&#39;</span><span class="token punctuation">,</span>\n  <span class="token function">setup</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    <span class="token comment">//使用ref，说明这个数组就是全局在面板中可以使用了</span>\n    <span class="token keyword">const</span> girls <span class="token operator">=</span> <span class="token function">ref</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token string">&#39;美女1&#39;</span><span class="token punctuation">,</span><span class="token string">&#39;美女2&#39;</span><span class="token punctuation">,</span><span class="token string">&#39;美女3&#39;</span><span class="token punctuation">]</span><span class="token punctuation">)</span>\n    <span class="token keyword">const</span> selectGirl <span class="token operator">=</span> <span class="token function">ref</span><span class="token punctuation">(</span><span class="token string">&#39;2&#39;</span><span class="token punctuation">)</span>\n    <span class="token comment">//设置一个函数</span>\n    <span class="token keyword">const</span> <span class="token function-variable function">selectGirlFun</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token parameter"><span class="token literal-property property">index</span><span class="token operator">:</span> number</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>\n      <span class="token comment">//改变selectGirl的值要加value</span>\n      <span class="token comment">//要得到值要加value ，这些都因为使用了ref函数</span>\n      selectGirl<span class="token punctuation">.</span>value <span class="token operator">=</span> girls<span class="token punctuation">.</span>value<span class="token punctuation">[</span>index<span class="token punctuation">]</span>\n    <span class="token punctuation">}</span>\n    <span class="token comment">//在标签中使用的变量要使用return</span>\n    <span class="token comment">//为什么要使用return，因为有的不需要在标签中使用的就不用return</span>\n   <span class="token keyword">return</span><span class="token punctuation">{</span>\n      girls<span class="token punctuation">,</span>\n      selectGirl<span class="token punctuation">,</span>\n      selectGirlFun\n    <span class="token punctuation">}</span>\n  <span class="token punctuation">}</span><span class="token punctuation">,</span>\n<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span>\n\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br></div></div><h5 id="_3-vue2和vue3生命周期钩子函数的不同" tabindex="-1"><a class="header-anchor" href="#_3-vue2和vue3生命周期钩子函数的不同" aria-hidden="true">#</a> 3: vue2和vue3生命周期钩子函数的不同</h5><ul><li><p><code>vue2</code>中的生命周期</p><ul><li><code>beforeCreate</code> 组件创建之前</li><li><code>created</code> 组件创建之后</li><li><code>beforeMount</code> 组价挂载到页面之前执行</li><li><code>mounted</code> 组件挂载到页面之后执行</li><li><code>beforeUpdate</code> 组件更新之前</li><li><code>updated</code> 组件更新之后</li></ul></li><li><p><code>vue3</code>中的生命周期</p><ul><li><code>setup</code> 开始创建组件</li><li><code>onBeforeMount</code> 组价挂载到页面之前执行</li><li><code>onMounted</code> 组件挂载到页面之后执行</li><li><code>onBeforeUpdate</code> 组件更新之前</li><li><code>onUpdated</code> 组件更新之后<br> 而且<code>Vue3.x</code> 生命周期在调用前需要先进行引入。<br> 如：</li></ul></li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">import</span> <span class="token punctuation">{</span>\n reactive<span class="token punctuation">,</span>\n toRefs<span class="token punctuation">,</span>\n onMounted<span class="token punctuation">,</span>\n onBeforeMount<span class="token punctuation">,</span>\n onBeforeUpdate<span class="token punctuation">,</span>\n onUpdated<span class="token punctuation">,</span>\n<span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&quot;vue&quot;</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><ul><li>来一个总的生命周期对比，这样更便于记忆</li></ul><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>Vue2--------------vue3\nbeforeCreate  -&gt; setup()\ncreated       -&gt; setup()\nbeforeMount   -&gt; onBeforeMount\nmounted       -&gt; onMounted\nbeforeUpdate  -&gt; onBeforeUpdate\nupdated       -&gt; onUpdated\nbeforeDestroy -&gt; onBeforeUnmount\ndestroyed     -&gt; onUnmounted\nactivated     -&gt; onActivated\ndeactivated   -&gt; onDeactivated\nerrorCaptured -&gt; onErrorCaptured\n\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p>除了这些钩子函数外，<code>Vue3.x</code>还增加了<code>onRenderTracked</code> 和<code>onRenderTriggered</code>函数。</p><h5 id="_3-vue3中新加入了typescript和pwa的支持" tabindex="-1"><a class="header-anchor" href="#_3-vue3中新加入了typescript和pwa的支持" aria-hidden="true">#</a> 3: vue3中新加入了TypeScript和PWA的支持</h5>',14),p={},t=(0,a(3744).Z)(p,[["render",function(n,s){return e}]])},3744:(n,s)=>{s.Z=(n,s)=>{const a=n.__vccOpts||n;for(const[n,e]of s)a[n]=e;return a}}}]);